Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;
    private readonly MockHttpMessageHandler _handler;
    private readonly DataFetcher _fetcher;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
        _handler = new MockHttpMessageHandler();
        _fetcher = new DataFetcher(new HttpClient(_handler));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        };

        var result = await _fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.NotFound);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await _fetcher.FetchAsync("https://example.com/missing"));
    }

    [TestMethod]
    public async Task FetchAsync_Cancelled_ThrowsOperationCancelled()
    {
        _handler.Response = new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("data")
        };

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await _fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal test double — avoids needing Moq
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public HttpResponseMessage Response { get; set; } = new(HttpStatusCode.OK);

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(Response);
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Async tests** | `async Task` return type — MSTest awaits them natively |
| **Timeouts** | `[Timeout(5000)]` + `_testContext.CancellationToken` — auto-cancels on timeout |
| **Cancellation** | Pre-cancelled `CancellationTokenSource` verifies the token is forwarded |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Constructor init** | `TestContext` injected via constructor (MSTest 3.6+), fields are `readonly` |
| **Sealed class** | Minor perf win, signals no inheritance needed |
| **No mocking library** | Custom `HttpMessageHandler` keeps dependencies minimal |
